Let's break down how to create a smooth, image-animated Snake game in C. We'll focus on key aspects for performance and clarity.

**1. Choose Your Graphics Library**

C lacks built-in graphics support. You need a library:

* **SDL (Simple DirectMedia Layer):**  Extremely popular, cross-platform, and well-suited for 2D games. [https://www.libsdl.org/](https://www.libsdl.org/)
* **SFML (Simple and Fast Multimedia Library):** Another excellent choice, known for its ease of use and modern C++ bindings (but works well with C too). [https://www.sfml-dev.org/](https://www.sfml-dev.org/)

For this example, we'll use SDL for its maturity and wide community support.

**2. Set Up Your Project**

* **Install SDL:** Follow the installation instructions on the SDL website for your operating system.
* **Create a Basic C Project:**
   - `main.c` (or your preferred filename)
   - Include `SDL2/SDL.h` (adjust path based on your installation).

**3. Core Game Logic (C Focus)**

Here's a simplified structure. We'll emphasize the C aspects and leave detailed SDL initialization and image loading for the next steps.

```c
#include <SDL2/SDL.h>
#include <stdlib.h>
#include <time.h>

// Constants
#define WIDTH 640
#define HEIGHT 480
#define BLOCK_SIZE 20
#define MAX_SNAKE_LENGTH 100

// Direction enum (important for readability)
typedef enum { UP, DOWN, LEFT, RIGHT } Direction;

// Structure for snake segments (position + previous for smooth movement)
typedef struct {
    int x, y;
    struct SnakePart* prev;
} SnakePart;

// Game state structure
typedef struct {
    SnakePart* head;
    int length;
    Direction direction;
} GameState;

// Function prototypes
void initGame(GameState* state);
void handleEvents(GameState* state);
void updateGame(GameState* state);
void renderGame(GameState* state, SDL_Renderer* renderer);

int main(int argc, char* argv[]) {
    if (SDL_Init(SDL_INIT_VIDEO) != 0) {
        SDL_LogError(SDL_LOG_CATEGORY_APPLICATION, "SDL initialization failed: %s", SDL_GetError());
        return 1;
    }

    SDL_Window* window = SDL_CreateWindow("Snake", SDL_WINDOWPOS_CENTERED, SDL_WINDOWPOS_CENTERED, WIDTH, HEIGHT, SDL_WINDOW_SHOWN);
    if (!window) {
        SDL_LogError(SDL_LOG_CATEGORY_APPLICATION, "Window creation failed: %s", SDL_GetError());
        SDL_Quit();
        return 1;
    }

    SDL_Renderer* renderer = SDL_CreateRenderer(window, -1, SDL_RENDERER_ACCELERATED);
    if (!renderer) {
        SDL_LogError(SDL_LOG_CATEGORY_APPLICATION, "Renderer creation failed: %s", SDL_GetError());
        SDL_DestroyWindow(window);
        SDL_Quit();
        return 1;
    }

    // Initialize game state
    GameState state;
    initGame(&state);

    bool running = true;
    clock_t lastUpdate = clock();

    while (running) {
        // Handle events (key presses, closes)
        handleEvents(&state);

        // Cap frame rate (important for smoothness)
        float deltaTime = (float)(clock() - lastUpdate) / CLOCKS_PER_SEC;
        lastUpdate = clock();
        if (deltaTime < 0.05) { // Aim for 20 FPS minimum
            updateGame(&state);
            renderGame(&state, renderer);
        }

        // Limit to 60 FPS max (adjust as needed)
        if (deltaTime > 1 / 60.0) SDL_Delay((Uint32)((1 / 60.0) - deltaTime * 1000));
    }

    // Clean up
    SDL_DestroyRenderer(renderer);
    SDL_DestroyWindow(window);
    SDL_Quit();
    return 0;
}

// ... (Implement the following functions)

void initGame(GameState* state) {
    // Initialize snake position, direction, etc.
    state->head = malloc(sizeof(SnakePart));
    state->head->x = WIDTH / 2 / BLOCK_SIZE * BLOCK_SIZE;
    state->head->y = HEIGHT / 2 / BLOCK_SIZE * BLOCK_SIZE;
    state->head->prev = NULL; // Start point
    state->length = 1;
    state->direction = RIGHT; // Initial direction
}

void handleEvents(GameState* state) {
    SDL_Event event;
    while (SDL_PollEvent(&event)) {
        if (event.type == SDL_QUIT) {
            running = false;
        } else if (event.type == SDL_KEYDOWN) {
            switch (event.key.keysym.sym) {
                case SDLK_UP: if (state->direction != DOWN) state->direction = UP; break;
                case SDLK_DOWN: if (state->direction != UP) state->direction = DOWN; break;
                case SDLK_LEFT: if (state->direction != RIGHT) state->direction = LEFT; break;
                case SDLK_RIGHT: if (state->direction != LEFT) state->direction = RIGHT; break;
            }
        }
    }
}

void updateGame(GameState* state) {
    // Move snake head based on direction
    SnakePart* newPart = malloc(sizeof(SnakePart));
    newPart->x = state->head->x;
    newPart->y = state->head->y;
    newPart->prev = state->head;
    state->head->prev = newPart;

    switch (state->direction) {
        case UP: state->head->y -= BLOCK_SIZE; break;
        case DOWN: state->head->y += BLOCK_SIZE; break;
        case LEFT: state->head->x -= BLOCK_SIZE; break;
        case RIGHT: state->head->x += BLOCK_SIZE; break;
    }

    // Collision detection (wall, self), score increment...
}

void renderGame(GameState* state, SDL_Renderer* renderer) {
    // Clear screen with background color
    SDL_SetRenderDrawColor(renderer, 0x00, 0x00, 0x00, 255); // Black
    SDL_RenderClear(renderer);

    // Draw snake segments using loaded images (see next step)
    // ... Iterate through snake parts, blit corresponding image

    // Draw food (another image)
    // ... Blit food image at random position

    SDL_RenderPresent(renderer);
}
```

**4. Image Handling with SDL**

* **Load Images:**
   ```c
